  public static abstract class Bool extends TLObject {
    public static final String TYPE = "Bool";

    public static ApiScheme.Bool readType(TLInputStream istream, TLContext context) throws Exception {
      int id = istream.readInt();
      istream.skip(-4);
      ApiScheme.Bool a = null;
      if (id == ApiScheme.boolFalse.ID) {
        a = new ApiScheme.boolFalse();
      } else if (id == ApiScheme.boolTrue.ID) {
        a = new ApiScheme.boolTrue();
      } else {

      }
      if (a != null) {
        a.read(istream, context);
      } else {
        throw new TLNotFoundException(id);
      }
      return a;
    }
  }

