  public static class game_ extends ApiScheme.Game {
    public static final int ID = 0xbdf9653b;
    public static final boolean IS_CONSTRUCTOR = true;
    public static final String NAME = "game";
    public int flags;
    public long id;
    public long access_hash;
    public String short_name;
    public String title;
    public String description;
    public ApiScheme.Photo photo;
    public ApiScheme.Document document = null;


    @Override
    public int getId() {
      return ID;
    }

    @Override
    public boolean isConstructor() {
      return IS_CONSTRUCTOR;
    }

    @Override
    public String getName() {
      return NAME;
    }

    @Override
    public void readParams(TLInputStream istream, TLContext context) throws Exception {
      flags = istream.readInt32();
      id = istream.readInt64();
      access_hash = istream.readInt64();
      short_name = istream.readTLString();
      title = istream.readTLString();
      description = istream.readTLString();
      photo = ApiScheme.Photo.readType(istream, context);
      if ((flags & 1) != 0) {
        document = ApiScheme.Document.readType(istream, context);
      }

    }

    @Override
    public void writeParams(TLOutputStream ostream) throws Exception {
      flags = document != null ? (flags | 1) : (flags & ~1);
      ostream.writeInt32(flags);
      ostream.writeInt64(id);
      ostream.writeInt64(access_hash);
      ostream.writeTLString(short_name);
      ostream.writeTLString(title);
      ostream.writeTLString(description);
      photo.write(ostream);
      if ((flags & 1) != 0) {
        document.write(ostream);
      }

    }

    @Override
    public JSONObject toJSON() {
      JSONObject _json = new JSONObject();
      _json.put("@id", getId());
      _json.put("@name", getName());
      _json.put("@type", TYPE);
      _json.put("flags", flags);
      _json.put("id", id);
      _json.put("access_hash", access_hash);
      _json.put("short_name", short_name);
      _json.put("title", title);
      _json.put("description", description);
      _json.put("photo", photo.toJSON());
      _json.put("document", document != null ? document.toJSON() : null);

      return _json;
    }

    @Override
    public String toString() {
      return toJSON().toString();
    }
  }


