  public static class pageBlockPhoto extends ApiScheme.PageBlock {
    public static final int ID = 0x1759c560;
    public static final boolean IS_CONSTRUCTOR = true;
    public static final String NAME = "pageBlockPhoto";
    public int flags;
    public long photo_id;
    public ApiScheme.PageCaption caption;
    public String url = null;
    public Long webpage_id;


    @Override
    public int getId() {
      return ID;
    }

    @Override
    public boolean isConstructor() {
      return IS_CONSTRUCTOR;
    }

    @Override
    public String getName() {
      return NAME;
    }

    @Override
    public void readParams(TLInputStream istream, TLContext context) throws Exception {
      flags = istream.readInt32();
      photo_id = istream.readInt64();
      caption = ApiScheme.PageCaption.readType(istream, context);
      if ((flags & 1) != 0) {
        url = istream.readTLString();
      }
      if ((flags & 1) != 0) {
        webpage_id = istream.readInt64();
      }

    }

    @Override
    public void writeParams(TLOutputStream ostream) throws Exception {
      flags = url != null ? (flags | 1) : (flags & ~1);
      flags = webpage_id != null ? (flags | 1) : (flags & ~1);
      ostream.writeInt32(flags);
      ostream.writeInt64(photo_id);
      caption.write(ostream);
      if ((flags & 1) != 0) {
        ostream.writeTLString(url);
      }
      if ((flags & 1) != 0) {
        ostream.writeInt64(webpage_id);
      }

    }

    @Override
    public JSONObject toJSON() {
      JSONObject _json = new JSONObject();
      _json.put("@id", getId());
      _json.put("@name", getName());
      _json.put("@type", TYPE);
      _json.put("flags", flags);
      _json.put("photo_id", photo_id);
      _json.put("caption", caption.toJSON());
      _json.put("url", url);
      _json.put("webpage_id", webpage_id);

      return _json;
    }

    @Override
    public String toString() {
      return toJSON().toString();
    }
  }


